import React from "react";
import styles from './Accordion.module.scss';

const Accordion = (props) => {

  return(
    <div className={styles.accordion}>
      <div className={styles.accordionContent}>
        <h4>{props.title}</h4>
      </div>
    </div>
  );
}

export default Accordion;
